CREATE OR REPLACE FUNCTION fpa_gos_re_test (ai_year bigint,ai_mount bigint,as_kep char,as_memno char) RETURNS bigint AS $body$
DECLARE

    ldc_value bigint;

BEGIN
  select sum(kh.money_return_post) into STRICT ldc_value
    from		sc_kep_t_monthly_receive kh
        ,sc_mem_m_ucf_member_group
        ,sc_mem_m_ucf_province
    where (kh.member_group_no = sc_mem_m_ucf_member_group.member_group_no)
    and (sc_mem_m_ucf_member_group.province_code = sc_mem_m_ucf_province.province_code)
    and (kh.receive_year = ai_year)
    and (kh.receive_month = ai_mount)
    and (kh.kep_method = as_kep)
    and (kh.membership_no = as_memno);

  return coalesce(ldc_value,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
